import { useState } from "react";

import facultyQuestions
  from "../../data/facultyQuestions";

import QuestionRenderer
  from "../../components/questionnaire/QuestionRenderer";

import FacultyLayout
  from "../../layouts/FacultyLayout";

function FacultyQuestionnaire() {

  const [selectedQuarter,
    setSelectedQuarter] =
    useState("");

  const [answers,
    setAnswers] =
    useState({});

  const handleAnswerChange =
    (
      sectionNo,
      questionIndex,
      value
    ) => {

      setAnswers(
        (prev) => ({
          ...prev,

          [`${sectionNo}_${questionIndex}`]:
            value
        })
      );
    };

  const handleSaveDraft =
    () => {

      if (!selectedQuarter) {

        alert(
          "Please Select Quarter"
        );

        return;
      }

      localStorage.setItem(

        `facultyDraft_${selectedQuarter}`,

        JSON.stringify(
          answers
        )
      );

      alert(
        "Draft Saved Successfully"
      );
    };

  const handleSubmit =
    () => {

      if (!selectedQuarter) {

        alert(
          "Please Select Quarter"
        );

        return;
      }

      console.log(
        answers
      );

      alert(
        "Questionnaire Submitted Successfully"
      );
    };

  return (

    <FacultyLayout>

      <div
        style={{
          maxWidth: "1200px",
          margin: "0 auto"
        }}
      >

        <h1>
          Faculty Questionnaire
        </h1>

        <p>
          Fill Quarterly IQAC Report
        </p>

        {/* Quarter Selection */}

        <div
          style={{
            background:
              "#ffffff",
            padding: "20px",
            borderRadius:
              "12px",
            marginBottom:
              "25px",
            boxShadow:
              "0 2px 8px rgba(0,0,0,0.1)"
          }}
        >

          <h3>
            Select Quarter
          </h3>

          <select
            value={
              selectedQuarter
            }
            onChange={
              (e) =>
                setSelectedQuarter(
                  e.target.value
                )
            }
            style={{
              width: "250px",
              padding: "12px",
              borderRadius:
                "8px"
            }}
          >

            <option value="">
              Select Quarter
            </option>

            <option value="Q1">
              Q1
            </option>

            <option value="Q2">
              Q2
            </option>

            <option value="Q3">
              Q3
            </option>

            <option value="Q4">
              Q4
            </option>

          </select>

        </div>

        {/* Sections */}

        {
          facultyQuestions.map(
            (section) => (

              <div
                key={
                  section.sectionNo
                }
                style={{
                  background:
                    "#ffffff",
                  padding:
                    "25px",
                  marginBottom:
                    "25px",
                  borderRadius:
                    "12px",
                  boxShadow:
                    "0 2px 8px rgba(0,0,0,0.1)"
                }}
              >

                <h2>
                  Section {
                    section.sectionNo
                  }
                </h2>

                <h3>
                  {
                    section.sectionTitle
                  }
                </h3>

                <hr />

                {
                  section.questions.map(
                    (
                      question,
                      index
                    ) => (

                      <div
                        key={
                          index
                        }
                        style={{
                          marginBottom:
                            "25px"
                        }}
                      >

                        <label
                          style={{
                            fontWeight:
                              "600"
                          }}
                        >
                          {
                            question.question
                          }
                        </label>

                        <QuestionRenderer
                          questionData={
                            question
                          }
                          value={
                            answers[
                              `${section.sectionNo}_${index}`
                            ]
                          }
                          onChange={
                            (
                              value
                            ) =>
                              handleAnswerChange(
                                section.sectionNo,
                                index,
                                value
                              )
                          }
                        />

                      </div>

                    )
                  )
                }

              </div>

            )
          )
        }

        {/* Action Buttons */}

        <div
          style={{
            display: "flex",
            gap: "15px",
            marginBottom:
              "50px"
          }}
        >

          <button
            onClick={
              handleSaveDraft
            }
            style={{
              padding:
                "12px 25px",
              border: "none",
              borderRadius:
                "8px",
              background:
                "#f59e0b",
              color: "#fff",
              cursor:
                "pointer",
              fontWeight:
                "600"
            }}
          >
            Save Draft
          </button>

          <button
            onClick={
              handleSubmit
            }
            style={{
              padding:
                "12px 25px",
              border: "none",
              borderRadius:
                "8px",
              background:
                "#10b981",
              color: "#fff",
              cursor:
                "pointer",
              fontWeight:
                "600"
            }}
          >
            Submit Questionnaire
          </button>

        </div>

      </div>

    </FacultyLayout>

  );
}

export default FacultyQuestionnaire;
